import{c as r,Q as t,j as o,m as s}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"How do I transfer ownership of my customer?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/transfer-ownership.md","filePath":"guide/recipes/portal/transfer-ownership.md","lastUpdated":1779094756000}'),n={name:"guide/recipes/portal/transfer-ownership.md"};function a(i,e,l,h,d,p){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-transfer-ownership-of-my-customer" tabindex="-1">How do I transfer ownership of my customer? <a class="header-anchor" href="#how-do-i-transfer-ownership-of-my-customer" aria-label="Permalink to &quot;How do I transfer ownership of my customer?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> only</p></div><p>There is exactly one Owner per customer. To replace yourself, you transfer ownership to another user — the system demotes you to Admin in the same operation.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Settings</strong> in the sidebar.</li><li>In the <strong>Organization</strong> tab, scroll to <strong>Ownership</strong>.</li><li>Click <strong>Transfer Ownership</strong>.</li><li>Pick the user who should become the new Owner. Only users who already hold the Admin role appear in the picker — promote them first if needed.</li><li>Type the confirmation string (&quot;transfer&quot;) and click <strong>Confirm Transfer</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The transfer is atomic — at the next page load, you are an Admin and the chosen user is the Owner. The new Owner sees an Owner-only banner on their next sign-in and immediately holds every Owner-only capability (promote/demote admins, delete customer).</p><div class="warning custom-block"><p class="custom-block-title">You cannot undo this without the new Owner&#39;s cooperation</p><p>If you transfer to the wrong person, you have to ask the new Owner to transfer it back. Confirm carefully.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./promote-to-admin">How do I promote someone to Admin?</a></li><li><a href="./../../concepts/roles-and-permissions">Roles &amp; Permissions reference</a></li></ul>',10)])])}const u=r(n,[["render",a]]);export{m as __pageData,u as default};
